arguments.argument:
if global.gamePaused=false
{
  if collision_rectangle(x,y-8,x+48,y+32,oNightmareEffect,0,1)
  {
    sprite_index=sNightmarePlatform
  }
  else
  {
    sprite_index=sNull
  }
  
  if bCanMove=true
  {
    if shiftTime>=shiftMax
    {
      if shiftSeq=0
      {
        if bPauseOnEnd=1
        {
          xVel=0
          yVel=0
          shiftSeq=1
        }
        else
          shiftSeq=1000
      }
      else if shiftSeq>=1 and shiftSeq<=20
        shiftSeq+=1
      else if shiftSeq>=21
      {
        shiftTime=0
        shiftSeq=0
        xVel=xDir
        yVel=yDir
        xVel*=-1
        yVel*=-1
        xDir=xVel
        yDir=yVel
      }
    }
    else
    {
      if prevX!=x or prevY!=y
      {
        prevX=x
        prevY=y
        shiftTime+=1
      }
    }
  }
}
